const country = $input.first().json;

// Define all content pieces for this country
const contentPlan = [
  // Pillar Guides
  {
    type: 'pillar-guide',
    slug: 'property-buying-guide',
    title: `Complete Property Buying Guide — ${country.country_name}`,
    category: 'property-buying',
    priority: 'P0',
  },
  {
    type: 'pillar-guide',
    slug: 'mortgage-guide',
    title: `Complete Mortgage Guide — ${country.country_name}`,
    category: 'mortgage',
    priority: 'P0',
  },
  // Blog Posts
  { type: 'blog', slug: 'first-home-buyer-guide', title: `First Home Buyer Guide ${country.country_name} 2026`, category: 'first-home', priority: 'P1' },
  { type: 'blog', slug: 'buying-costs-explained', title: `Property Buying Costs in ${country.country_name} Explained`, category: 'costs', priority: 'P1' },
  { type: 'blog', slug: '${country.tax_term.replace(/ /g, '-')}-explained', title: `${country.tax_term.charAt(0).toUpperCase() + country.tax_term.slice(1)} in ${country.country_name} Explained`, category: 'taxes', priority: 'P1' },
  { type: 'blog', slug: 'government-grants-schemes', title: `Government Grants and Schemes for Buyers in ${country.country_name}`, category: 'grants', priority: 'P1' },
  { type: 'blog', slug: 'property-inspection-checklist', title: `Property Inspection Checklist for ${country.country_name}`, category: 'inspections', priority: 'P2' },
  { type: 'blog', slug: 'mortgage-types-compared', title: `Types of Mortgages in ${country.country_name} Compared`, category: 'loan-types', priority: 'P1' },
  { type: 'blog', slug: 'rent-vs-buy-analysis', title: `Renting vs Buying in ${country.country_name}: Full Analysis`, category: 'rent-vs-buy', priority: 'P2' },
  { type: 'blog', slug: 'property-investment-guide', title: `Property Investment Guide for ${country.country_name}`, category: 'investment', priority: 'P2' },
  { type: 'blog', slug: 'refinancing-guide', title: `When and How to Refinance Your Mortgage in ${country.country_name}`, category: 'refinancing', priority: 'P2' },
  { type: 'blog', slug: 'common-buying-mistakes', title: `10 Common Property Buying Mistakes in ${country.country_name}`, category: 'mistakes', priority: 'P2' },
  // FAQ Hub
  {
    type: 'faq-hub',
    slug: 'faqs',
    title: `${country.country_name} Mortgage & Property FAQs`,
    category: 'general',
    priority: 'P1',
  },
];

return contentPlan.map(item => ({
  json: {
    ...country,
    ...item,
    url: item.type === 'faq-hub'
      ? `${country.country_slug}/faqs/`
      : item.type === 'pillar-guide'
        ? `${country.country_slug}/${item.slug}/`
        : `${country.country_slug}/blog/${item.slug}/`,
  }
}));

const item = $('Build Content Plan (13 items)').first().json;
const briefResponse = $input.first().json;
const briefText = briefResponse.content[0].text;

// Build the full generation prompt based on content type
let promptTemplate;
if (item.type === 'pillar-guide') {
  promptTemplate = `You are an expert mortgage writer for urmortgage.online. Write a 2,500-3,000 word pillar guide. Country: ${item.country_name}. Title: ${item.title}. Type: ${item.category}. Slug: ${item.slug}. Country slug: ${item.country_slug}. Currency: ${item.currency_symbol}. Tax term: ${item.tax_term}. Deposit term: ${item.deposit_term}. Central bank: ${item.central_bank}. Brief: ${briefText}. Output ONLY valid Markdown with YAML frontmatter starting with ---. Include published: true in frontmatter.`;
} else if (item.type === 'faq-hub') {
  promptTemplate = `You are an expert mortgage writer for urmortgage.online. Generate 50 FAQs for ${item.country_name}. Country slug: ${item.country_slug}. Currency: ${item.currency_symbol} (${item.currency_code}). Tax term: ${item.tax_term}. Central bank: ${item.central_bank}. Categories: buying-process, financing, costs, legal, investment, general. Output ONLY valid Markdown with YAML frontmatter starting with ---. Include published: true in frontmatter.`;
} else {
  promptTemplate = `You are an expert mortgage writer for urmortgage.online. Write a 1,200-1,800 word blog post. Country: ${item.country_name}. Title: ${item.title}. Slug: ${item.slug}. Category: ${item.category}. Country slug: ${item.country_slug}. Currency: ${item.currency_symbol}. Tax term: ${item.tax_term}. Brief: ${briefText}. Include internal links to /${item.country_slug}/property-buying-guide/, /${item.country_slug}/mortgage-guide/, /${item.country_slug}/faqs/, /calculator/?country=${item.country_iso.toLowerCase()}. Output ONLY valid Markdown with YAML frontmatter starting with ---. Include published: true in frontmatter.`;
}

return [{
  json: {
    ...item,
    brief: briefText,
    prompt: promptTemplate,
  }
}];
